window.docContents[148].resolve({"/Lecture-1___-Motivation-and-Propositional-Logic/#lecture-1":{"contents":"This lecture motivates formal software verification and reviews propositional logic, following chapter 1 of How To Prove It with Lean (HTPIwL). It presents the connectives, the classical equivalences, and the first structured proofs in Lean.\n\n\n\n\n\n\n\n\n\n\n\n\n\n","context":"Formal Software Verification","header":"1. Lecture 1: Motivation and Propositional Logic","id":"/Lecture-1___-Motivation-and-Propositional-Logic/#lecture-1"}});